solution_code:
#include <stdio.h>

int count_elements(int *begin, int *end) {
    return (int)(end - begin);
}

int main(void) {
    {
        int arr[] = {1, 2, 3};
        printf("%d\n", (int)(count_elements(arr, arr)));
    }
    {
        int arr[] = {42};
        printf("%d\n", (int)(count_elements(arr, arr + 1)));
    }
    {
        int arr[] = {10, 20, 30, 40, 50};
        printf("%d\n", (int)(count_elements(arr, arr + 5)));
    }
    {
        int arr[] = {1, 2, 3, 4, 5, 6, 7};
        printf("%d\n", (int)(count_elements(arr + 2, arr + 5)));
    }
    return 0;
}

