#include <stdio.h>

/* == EXEMPLE ================================================
 * Trouver le min d'un tableau via pointeur qui avance
 * p++ deplace le pointeur de sizeof(int) octets.
 * =========================================================== */
int example_min(const int *arr, int n) {
    const int *p = arr;
    const int *end = arr + n;
    int min = *p;
    p++;
    while (p < end) {
        if (*p < min) min = *p;
        p++;
    }
    return min;
}
void example_demo(void) {
    int data[] = {8, 3, 5, 1, 9};
    printf("Min : %d\n", example_min(data, 5));
}
